package com.orellano.biblia360.daoSQLite.sql.spa;

public final class Load1Juan {
  public Load1Juan() {}
  public static final String SQL_PARTE_1 = 
    "INSERT INTO Versiculo (\n" +
    "    codLengua_vscl, codVersion_vscl, codLibro_vscl, codCapitulo_vscl, codVersiculo_vscl, encabezado_vscl,\n" +
    "    contenido_vscl,\n" +
    "    parrafo_vscl, codLengua_vscl_ltr, codVersion_vscl_ltr, codLectura_vscl_ltr)\n" +
    "VALUES\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 1, 'La palabra de vida', 'Lo que era desde el principio, lo que hemos oído, lo que hemos visto con nuestros ojos, lo que hemos contemplado, y palparon nuestras manos tocante al Verbo de vida', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 2, NULL, '(porque la vida fue manifestada, y la hemos visto, y testificamos, y os anunciamos la vida eterna, la cual estaba con el Padre, y se nos manifestó);', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 3, NULL, 'lo que hemos visto y oído, eso os anunciamos, para que también vosotros tengáis comunión con nosotros; y nuestra comunión verdaderamente es con el Padre, y con su Hijo Jesucristo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 4, NULL, 'Estas cosas os escribimos, para que vuestro gozo sea cumplido.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 5, 'Dios es luz', 'Este es el mensaje que hemos oído de él, y os anunciamos: Dios es luz, y no hay ningunas tinieblas en él.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 6, NULL, 'Si decimos que tenemos comunión con él, y andamos en tinieblas, mentimos, y no practicamos la verdad;', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 7, NULL, 'pero si andamos en luz, como él está en luz, tenemos comunión unos con otros, y la sangre de Jesucristo su Hijo nos limpia de todo pecado.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 8, NULL, 'Si decimos que no tenemos pecado, nos engañamos a nosotros mismos, y la verdad no está en nosotros.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 9, NULL, 'Si confesamos nuestros pecados, él es fiel y justo para perdonar nuestros pecados, y limpiarnos de toda maldad.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 1, 10, NULL, 'Si decimos que no hemos pecado, le hacemos a él mentiroso, y su palabra no está en nosotros.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 1, 'Cristo, nuestro abogado', 'Hijitos míos, estas cosas os escribo para que no pequéis; y si alguno hubiere pecado, abogado tenemos para con el Padre, a Jesucristo el justo.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 2, NULL, 'Y él es la propiciación por nuestros pecados; y no solamente por los nuestros, sino también por los de todo el mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 3, NULL, 'Y en esto sabemos que nosotros le conocemos, si guardamos sus mandamientos.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 4, NULL, 'El que dice: Yo le conozco, y no guarda sus mandamientos, el tal es mentiroso, y la verdad no está en él;', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 5, NULL, 'pero el que guarda su palabra, en este verdaderamente el amor de Dios se ha perfeccionado; por esto sabemos que estamos en él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 6, NULL, 'El que dice que permanece en él, debe andar como él anduvo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 7, 'El nuevo mandamiento', 'Hermanos, no os escribo mandamiento nuevo, sino el mandamiento antiguo que habéis tenido desde el principio; este mandamiento antiguo es la palabra que habéis oído desde el principio.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 8, NULL, 'Sin embargo, os escribo un mandamiento nuevo, que es verdadero en él y en vosotros, porque las tinieblas van pasando, y la luz verdadera ya alumbra.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 9, NULL, 'El que dice que está en la luz, y aborrece a su hermano, está todavía en tinieblas.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 10, NULL, 'El que ama a su hermano, permanece en la luz, y en él no hay tropiezo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 11, NULL, 'Pero el que aborrece a su hermano está en tinieblas, y anda en tinieblas, y no sabe a dónde va, porque las tinieblas le han cegado los ojos.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 12, NULL, 'Os escribo a vosotros, hijitos, porque vuestros pecados os han sido perdonados por su nombre.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 13, NULL, 'Os escribo a vosotros, padres, porque conocéis al que es desde el principio. Os escribo a vosotros, jóvenes, porque habéis vencido al maligno. Os escribo a vosotros, hijitos, porque habéis conocido al Padre.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 14, NULL, 'Os he escrito a vosotros, padres, porque habéis conocido al que es desde el principio. Os he escrito a vosotros, jóvenes, porque sois fuertes, y la palabra de Dios permanece en vosotros, y habéis vencido al maligno.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 15, NULL, 'No améis al mundo, ni las cosas que están en el mundo. Si alguno ama al mundo, el amor del Padre no está en él.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 16, NULL, 'Porque todo lo que hay en el mundo, los deseos de la carne, los deseos de los ojos, y la vanagloria de la vida, no proviene del Padre, sino del mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 17, NULL, 'Y el mundo pasa, y sus deseos; pero el que hace la voluntad de Dios permanece para siempre.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 18, 'El anticristo', 'Hijitos, ya es el último tiempo; y según vosotros oísteis que el anticristo viene, así ahora han surgido muchos anticristos; por esto conocemos que es el último tiempo.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 19, NULL, 'Salieron de nosotros, pero no eran de nosotros; porque si hubiesen sido de nosotros, habrían permanecido con nosotros; pero salieron para que se manifestase que no todos son de nosotros.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 20, NULL, 'Pero vosotros tenéis la unción del Santo, y conocéis todas las cosas.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 21, NULL, 'No os he escrito como si ignoraseis la verdad, sino porque la conocéis, y porque ninguna mentira procede de la verdad.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 22, NULL, '¿Quién es el mentiroso, sino el que niega que Jesús es el Cristo? Este es anticristo, el que niega al Padre y al Hijo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 23, NULL, 'Todo aquel que niega al Hijo, tampoco tiene al Padre. El que confiesa al Hijo, tiene también al Padre.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 24, NULL, 'Lo que habéis oído desde el principio, permanezca en vosotros. Si lo que habéis oído desde el principio permanece en vosotros, también vosotros permaneceréis en el Hijo y en el Padre.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 25, NULL, 'Y esta es la promesa que él nos hizo, la vida eterna.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 26, NULL, 'Os he escrito esto sobre los que os engañan.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 27, NULL, 'Pero la unción que vosotros recibisteis de él permanece en vosotros, y no tenéis necesidad de que nadie os enseñe; así como la unción misma os enseña todas las cosas, y es verdadera, y no es mentira, según ella os ha enseñado, permaneced en él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 28, NULL, 'Y ahora, hijitos, permaneced en él, para que cuando se manifieste, tengamos confianza, para que en su venida no nos alejemos de él avergonzados.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 2, 29, NULL, 'Si sabéis que él es justo, sabed también que todo el que hace justicia es nacido de él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 1, 'Hijos de Dios', 'Mirad cuál amor nos ha dado el Padre, para que seamos llamados hijos de Dios; por esto el mundo no nos conoce, porque no le conoció a él.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 2, NULL, 'Amados, ahora somos hijos de Dios, y aún no se ha manifestado lo que hemos de ser; pero sabemos que cuando él se manifieste, seremos semejantes a él, porque le veremos tal como él es.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 3, NULL, 'Y todo aquel que tiene esta esperanza en él, se purifica a sí mismo, así como él es puro.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 4, NULL, 'Todo aquel que comete pecado, infringe también la ley; pues el pecado es infracción de la ley.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 5, NULL, 'Y sabéis que él apareció para quitar nuestros pecados, y no hay pecado en él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 6, NULL, 'Todo aquel que permanece en él, no peca; todo aquel que peca, no le ha visto, ni le ha conocido.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 7, NULL, 'Hijitos, nadie os engañe; el que hace justicia es justo, como él es justo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 8, NULL, 'El que practica el pecado es del diablo; porque el diablo peca desde el principio. Para esto apareció el Hijo de Dios, para deshacer las obras del diablo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 9, NULL, 'Todo aquel que es nacido de Dios, no practica el pecado, porque la simiente de Dios permanece en él; y no puede pecar, porque es nacido de Dios.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 10, NULL, 'En esto se manifiestan los hijos de Dios, y los hijos del diablo: todo aquel que no hace justicia, y que no ama a su hermano, no es de Dios.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 11, NULL, 'Porque este es el mensaje que habéis oído desde el principio: Que nos amemos unos a otros.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 12, NULL, 'No como Caín, que era del maligno y mató a su hermano. ¿Y por qué causa le mató? Porque sus obras eran malas, y las de su hermano justas.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 13, NULL, 'Hermanos míos, no os extrañéis si el mundo os aborrece.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 14, NULL, 'Nosotros sabemos que hemos pasado de muerte a vida, en que amamos a los hermanos. El que no ama a su hermano, permanece en muerte.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 15, NULL, 'Todo aquel que aborrece a su hermano es homicida; y sabéis que ningún homicida tiene vida eterna permanente en él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 16, NULL, 'En esto hemos conocido el amor, en que él puso su vida por nosotros; también nosotros debemos poner nuestras vidas por los hermanos.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 17, NULL, 'Pero el que tiene bienes de este mundo y ve a su hermano tener necesidad, y cierra contra él su corazón, ¿cómo mora el amor de Dios en él?', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 18, NULL, 'Hijitos míos, no amemos de palabra ni de lengua, sino de hecho y en verdad.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 19, NULL, 'Y en esto conocemos que somos de la verdad, y aseguraremos nuestros corazones delante de él;', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 20, NULL, 'pues si nuestro corazón nos reprende, mayor que nuestro corazón es Dios, y él sabe todas las cosas.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 21, NULL, 'Amados, si nuestro corazón no nos reprende, confianza tenemos en Dios;', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 22, NULL, 'y cualquiera cosa que pidiéremos la recibiremos de él, porque guardamos sus mandamientos, y hacemos las cosas que son agradables delante de él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 23, NULL, 'Y este es su mandamiento: Que creamos en el nombre de su Hijo Jesucristo, y nos amemos unos a otros como nos lo ha mandado.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 3, 24, NULL, 'Y el que guarda sus mandamientos, permanece en Dios, y Dios en él. Y en esto sabemos que él permanece en nosotros, por el Espíritu que nos ha dado.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 1, 'El Espíritu de Dios y el espíritu del anticristo', 'Amados, no creáis a todo espíritu, sino probad los espíritus si son de Dios; porque muchos falsos profetas han salido por el mundo.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 2, NULL, 'En esto conoced el Espíritu de Dios: Todo espíritu que confiesa que Jesucristo ha venido en carne, es de Dios;', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 3, NULL, 'y todo espíritu que no confiesa que Jesucristo ha venido en carne, no es de Dios; y este es el espíritu del anticristo, el cual vosotros habéis oído que viene, y que ahora ya está en el mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 4, NULL, 'Hijitos, vosotros sois de Dios, y los habéis vencido; porque mayor es el que está en vosotros, que el que está en el mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 5, NULL, 'Ellos son del mundo; por eso hablan del mundo, y el mundo los oye.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 6, NULL, 'Nosotros somos de Dios; el que conoce a Dios, nos oye; el que no es de Dios, no nos oye. En esto conocemos el espíritu de verdad y el espíritu de error.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 7, 'Dios es amor', 'Amados, amémonos unos a otros; porque el amor es de Dios. Todo aquel que ama, es nacido de Dios, y conoce a Dios.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 8, NULL, 'El que no ama, no ha conocido a Dios; porque Dios es amor.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 9, NULL, 'En esto se mostró el amor de Dios para con nosotros, en que Dios envió a su Hijo unigénito al mundo, para que vivamos por él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 10, NULL, 'En esto consiste el amor: no en que nosotros hayamos amado a Dios, sino en que él nos amó a nosotros, y envió a su Hijo en propiciación por nuestros pecados.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 11, NULL, 'Amados, si Dios nos ha amado así, debemos también nosotros amarnos unos a otros.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 12, NULL, 'Nadie ha visto jamás a Dios. Si nos amamos unos a otros, Dios permanece en nosotros, y su amor se ha perfeccionado en nosotros.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 13, NULL, 'En esto conocemos que permanecemos en él, y él en nosotros, en que nos ha dado de su Espíritu.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 14, NULL, 'Y nosotros hemos visto y testificamos que el Padre ha enviado al Hijo, el Salvador del mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 15, NULL, 'Todo aquel que confiese que Jesús es el Hijo de Dios, Dios permanece en él, y él en Dios.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 16, NULL, 'Y nosotros hemos conocido y creído el amor que Dios tiene para con nosotros. Dios es amor; y el que permanece en amor, permanece en Dios, y Dios en él.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 17, NULL, 'En esto se ha perfeccionado el amor en nosotros, para que tengamos confianza en el día del juicio; pues como él es, así somos nosotros en este mundo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 18, NULL, 'En el amor no hay temor, sino que el perfecto amor echa fuera el temor; porque el temor lleva en sí castigo. De donde el que teme, no ha sido perfeccionado en el amor.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 19, NULL, 'Nosotros le amamos a él, porque él nos amó primero.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 20, NULL, 'Si alguno dice: Yo amo a Dios, y aborrece a su hermano, es mentiroso. Pues el que no ama a su hermano a quien ha visto, ¿cómo puede amar a Dios a quien no ha visto?', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 4, 21, NULL, 'Y nosotros tenemos este mandamiento de él: El que ama a Dios, ame también a su hermano.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 1, 'La fe que vence al mundo', 'Todo aquel que cree que Jesús es el Cristo, es nacido de Dios; y todo aquel que ama al que engendró, ama también al que ha sido engendrado por él.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 2, NULL, 'En esto conocemos que amamos a los hijos de Dios, cuando amamos a Dios, y guardamos sus mandamientos.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 3, NULL, 'Pues este es el amor a Dios, que guardemos sus mandamientos; y sus mandamientos no son gravosos.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 4, NULL, 'Porque todo lo que es nacido de Dios vence al mundo; y esta es la victoria que ha vencido al mundo, nuestra fe.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 5, NULL, '¿Quién es el que vence al mundo, sino el que cree que Jesús es el Hijo de Dios?', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 6, 'El testimonio del Espíritu', 'Este es Jesucristo, que vino mediante agua y sangre; no mediante agua solamente, sino mediante agua y sangre. Y el Espíritu es el que da testimonio; porque el Espíritu es la verdad.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 7, NULL, 'Porque tres son los que dan testimonio en el cielo: el Padre, el Verbo y el Espíritu Santo; y estos tres son uno.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 8, NULL, 'Y tres son los que dan testimonio en la tierra: el Espíritu, el agua y la sangre; y estos tres concuerdan.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 9, NULL, 'Si recibimos el testimonio de los hombres, mayor es el testimonio de Dios; porque este es el testimonio con que Dios ha testificado acerca de su Hijo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 10, NULL, 'El que cree en el Hijo de Dios, tiene el testimonio en sí mismo; el que no cree a Dios, le ha hecho mentiroso, porque no ha creído en el testimonio que Dios ha dado acerca de su Hijo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 11, NULL, 'Y este es el testimonio: que Dios nos ha dado vida eterna; y esta vida está en su Hijo.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 12, NULL, 'El que tiene al Hijo, tiene la vida; el que no tiene al Hijo de Dios no tiene la vida.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 13, 'El conocimiento de la vida eterna', 'Estas cosas os he escrito a vosotros que creéis en el nombre del Hijo de Dios, para que sepáis que tenéis vida eterna, y para que creáis en el nombre del Hijo de Dios.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 14, NULL, 'Y esta es la confianza que tenemos en él, que si pedimos alguna cosa conforme a su voluntad, él nos oye.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 15, NULL, 'Y si sabemos que él nos oye en cualquiera cosa que pidamos, sabemos que tenemos las peticiones que le hayamos hecho.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 16, NULL, 'Si alguno viere a su hermano cometer pecado que no sea de muerte, pedirá, y Dios le dará vida; esto es para los que cometen pecado que no sea de muerte. Hay pecado de muerte, por el cual yo no digo que se pida.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 17, NULL, 'Toda injusticia es pecado; pero hay pecado no de muerte.', 0, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 18, NULL, 'Sabemos que todo aquel que ha nacido de Dios, no practica el pecado, pues Aquel que fue engendrado por Dios le guarda, y el maligno no le toca.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 19, NULL, 'Sabemos que somos de Dios, y el mundo entero está bajo el maligno.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 20, NULL, 'Pero sabemos que el Hijo de Dios ha venido, y nos ha dado entendimiento para conocer al que es verdadero; y estamos en el verdadero, en su Hijo Jesucristo. Este es el verdadero Dios, y la vida eterna.', 1, 'spa', 'RVR1960', NULL),\n" +
    "('spa', 'RVR1960', '1 Jn', 5, 21, NULL, 'Hijitos, guardaos de los ídolos. Amén.', 0, 'spa', 'RVR1960', NULL);\n"
;

}